import{_ as a,o as t,c as r,j as p,a as S,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"认知诃学","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/学识类/认知诃学.md","filePath":"4.资源分区/6.技艺及称号/学识类/认知诃学.md"}'),o={name:"4.资源分区/6.技艺及称号/学识类/认知诃学.md"};function s(d,e,i,l,_,c){return t(),r("div",null,[...e[0]||(e[0]=[p("h1",{id:"认知诃学",tabindex:"-1"},[S("认知诃学 "),p("a",{class:"header-anchor",href:"#认知诃学","aria-label":'Permalink to "认知诃学"'},"​")],-1),p("table",{class:"bannerparthead"},[p("tbody",null,[p("tr",{id:"hdr"},[p("td",{class:"runninghead",nowrap:""},"TMD：新秩序004")])])],-1),n('<h1 id="认知诃学-1" tabindex="-1">认知诃学 <a class="header-anchor" href="#认知诃学-1" aria-label="Permalink to &quot;认知诃学&quot;">​</a></h1><p>认知诃学</p><p>认知（cognition）在心理学中是指通过形成概念、知觉、判断或想象等心理活动来获取知识的过程，即思维进行信息处理的心理功能。具体表现为人类感知世界并将观察到的现象理解为现实的概念，当足够多的人集体感知到某个概念时，这个概念就会变成“事实”，从而影响到自己和整个世界。认知也可以指他人或社会基于对一个人各角度的感知，给出的其形象的集合。而认知诃学就是研究认知如何运行、如何影响现实的一个研究项目。目前认知诃学研究方向分为两种，通过对个人认知改造认变个人与通过影响群体认知影响群体行动。通过研究认知诃学并配合心灵方面的超自然能力就可以这两种研究方向实现。（心灵方面的超自然能力范例：人格面具）</p><p>对认知诃学完全学习并对进行研究需要在心理学与社会学这两门学科上获得博士学位，根据认知诃学的学习需求，需要依次获得心理学硕士学位、社会学硕士学位、心理学博士学位、社会学博士学位，并且每次获得学位后对认知诃学均有一定研究。在进行认知诃学相关检定时，对应检定为【智力—主专业：认知诃学—副专业：非心智类技能下的心灵方面的超自然能力专业（如果拥有人格面具能力可以用人格面具专业作为副专业）】。</p><p>认知诃学对应学历学习资料：</p><p>———————————————————————————————————————</p><p>心理学硕士</p><p>资料价格：D+500/10XP</p><p>学习前提：学识3、心灵学1</p><p>【认知档案】</p><p>通过对不同人对自我的认知进行研究记录并整理成资料档案，档案按九个子分类进行分类，分别为心智大类：智力类、感知类、决心类；互动大类：风度类、操控类、沉着类；生理大类：力量类、敏捷类、耐力类。每个子类都有单独档案资料量级，初始都为零级。三份同大类的同级别子类档案会自动合成一个同级别该大类的资料档案量级。 资料档案可通过两种方式获得，第一种是通过【200÷智力】天的研究可总结一份指定子类的资料档案（天数结果向上取整），第二种是消耗1XP快速研究可总结一份指定子类的资料档案量级。</p><p>【个体认知影响】</p><p>认知诃学在心理治疗上的初步运用，在对目标过往经历和近期心理状态后，可针对性为其设计一套实验性认知影响方案，每次影响需要以谈话和催眠的形式进行延长检定对抗目标的决心属性，每次延长检定时间为一小时，当累计成功数超过目标的决心时影响成功，在这个过程中目标对影响有所抵抗的意向，可通过意志豁免抵消单次的延长检定成功数。当成功对目标的认知造成影响后，可使目标在不影响记忆和基本性格的情况下暂时治愈纯心理类疾病，并在不影响基本性格的前提下获得一种优秀性格，这种优秀性格可使目标在一种认知档案子类（除了生理大类下属的三个子分类）单一一种对应属性的相关检定上获得【目标对应属性/影响者智力属性（两者取低）上附加成功×对应子类的档案资料量级（上限为1）】点的士气加值，这种影响能够持续一周，但是在短时间内只能为一个目标设计影响方案并对其造成影响，也无法设计影响自身的影响方案，以上效果视为等于技艺等级的思维控制效果。特殊的是当影响者具有心灵方面的超自然能力也可以在目标失去意识的状态下通过能力直接影响目标。</p><p>———————————————————————————————————————</p><p>社会学硕士</p><p>资料价格：C+1000/20XP</p><p>学习前提：学识5、社会学1、任意认知档案的子类档案资料量级达到一级</p><p>【集体认知影响】</p><p>认知诃学在社会学上的初步运用，在对被影响的目标群体共同点和心理相似处后，可针对性为其设计一套实验性认知影响方案，每次影响需要以演讲、培训等群体交互行为的形式进行延长检定对抗目标群体内每位个体的决心属性，每次延长检定时间为一小时，当累计成功数超过目标的决心时影响成功，在这个过程中某位个体对影响有所抵抗的意向，可通过意志豁免抵消每次作用自身部分的延长检定成功数。当成功对目标群体的认知造成影响后，可使目标群体在不影响记忆和基本性格的情况下暂时治愈纯心理类疾病，并在不影响基本性格的前提下获得多种优秀性格，这些优秀性格可使目标群体在一种认知档案大类（除了生理大类）下对应三种属性的某一种属性的相关检定上获得【目标对应属性/影响者智力（两者取低）上附加成功×对应子类/大类的档案资料量级（上限为2）】点的士气加值，这种影响持续一周，但是和个体认知影响一样无法作用于自身，以上效果视为等于技艺等级的思维控制效果。</p><p>【认知防火墙】</p><p>在对认知诃学有一定了解后，开始有意识自主训练并构筑认知层面的防护手段，可以防止一些心灵来源的负面效果，并且不会阻止心灵来源的正面效果，但是对于心灵来源的正负面混合效果会按负面效果一般防止其生效，这视为等于技艺等级的心灵来源免疫。</p><p>———————————————————————————————————————</p><p>心理学博士</p><p>资料价格：B+2000/40XP</p><p>学习前提：学识8、心灵学3、任意认知档案的子类档案资料量级达到二级</p><p>【认知改造】</p><p>以认知影响为基础的发展出来认知改造技术，其前提还是了解个体目标的过往经历和近期心理状态或目标群体共同点和心理相似处后，可针对性为其设计一套认知改造方案，每次改造需要以谈话、催眠、演讲、培训等交互行为的形式进行延长检定对抗目标群体内每位个体的决心属性，每次延长检定时间为一小时，当累计成功数超过目标的决心时改造成功，在这个过程中某位个体对影响有所抵抗的意向，可通过意志豁免抵消每次作用自身部分的延长检定成功数。当成功将目标的认知改造后，可使目标遗忘或改变几种类型的记忆并将性格改变，通常是以治疗和优化为目的，遗忘或改变的记忆往往是会影响其心理健康的心理阴影，而性格上的改变能使目标在生理属性、心智属性或者互动属性的相关检定上获得【目标对应属性/改造者智力属性（两者取低）上附加成功×对应子类/大类的档案资料量级（上限为3）】点的士气加值。此外通常情况下和认知影响一样无法作用于自身，只有拥有人格面具的能力才能作用自身，以上效果视为等于技艺等级的思维控制效果。</p><p>【认知改造扩展技术—认知改变肉体】</p><p>发动前提：心灵方面的超自然能力（心灵方面的超自然能力范例：人格面具）</p><p>当改造者拥有心灵方面的超自然能力时，可在进行认知改造时加入本技术，能在原本的改造效果上使目标的生理属性获得加值或承受减值，并使肉体发生变化，同属碳基生物分类都在变化范围内，而体积变化范围为原体积基础上范围向上增加一倍，向下变小到一半，这种外形、体积变化并不会影响原本的魅力和生命值，这种变化效果持续时间基于认知改造的持续，会随着认知改造生效而随着失效，以上效果视为B级影响心灵来源的伪装效果。</p><p>———————————————————————————————————————</p><p>社会学博士</p><p>资料价格：A+4000/80XP</p><p>学习前提：学识11、社会学3、任意认知档案的子类档案资料量级达到三级</p><p>【认知扭曲】</p><p>以认知改造为基础的发展出来认知扭曲技术，该技术需要了解整个社会的认知后，可设计整个社会内的任意存在发动的认知扭曲方案，并且可设计多套方案备用，依旧是以谈话、催眠、演讲、培训等交互行为的形式进行延长检定对抗目标群体内每位个体的决心属性，每次延长检定时间为一小时，当累计成功数超过目标的决心时扭曲成功，在这个过程中某位个体对影响有所抵抗的意向，可通过意志豁免抵消每次作用自身部分的延长检定成功数。当成功将目标的认知扭曲后，可使目标记忆和性格扭曲成方案中预设的记忆，使目标在生理属性、心智属性或互动属性的相关检定上获得【目标对应属性/改造者智力属性（两者取低）上附加成功×对应子类/大类的档案资料量级（上限为5）】点的士气加值。此外通常情况下和认知影响一样无法作用于自身，只有拥有人格面具的能力才能作用自身，以上效果视为等于技艺等级的思维控制效果。同时作为以认知改造为基础发展出的技术，可在满足发动前提的情况下将【认知改造扩展技术—认知改变肉体】结合到认知扭曲当中发动，并使其效果持续时间基于认知扭曲的持续，会随着认知扭曲生效而随着失效。</p><p>【认知扭曲扩展技术—扭曲感染】</p><p>发动前提：具有与心灵相关的能量池</p><p>以认知扭曲为基础的发展出来间接将认知扭曲技术，以视频、录音、文字等形式制作可以将认知扭曲作用于观看者的扭曲媒介，每次制作需要消耗一个小时和1点心灵相关的能量，并且只有你亲自制造的那份媒介具有作用，其余复制品没有任何作用。以这种方式发动的【认知扭曲】会保留原本一切效果的，但是会根据社会认知的变化程度使扭曲媒介的有效期在二十天到三十天间浮动，并且同一份扭曲媒介对于每个人只能生效一次。</p><p>【认知观测】</p><p>发动前提：心灵方面的超自然能力</p><p>当改造者拥有心灵方面的超自然能力时，可借助能力对个体认知和集体认知进行观测，这意味着可以直接通过对认知的观测来完成从【认知影响】到【认知扭曲】一系列技术的发动前提，并且也可以通过对个人认知的观测精准定位其位置，这可以视为一种强感知方式。</p><p>———————————————————————————————————————</p><p>认知诃学研究者</p><p>资料价格：SSSSS+40000/800XP</p><p>学习前提：学识14、心理学5、社会学5、任意认知档案的子类档案资料量级达到四级</p><p>【认知操控】</p><p>完全掌握从【认知影响】到【认知扭曲】一系列技术，现在起在所有【档案资料量级】相关判定上没有上限限制，所有效果的持续时间也可以释放时从一周到一年的期间自由决定，并且一旦效果生效后就不会自然解除，这意味着【认知改造】与【认知扭曲】不再会因为冲击性行为而自动解除。</p><p>【认知操控扩展技术—模因制成】</p><p>发动前提：心灵方面的超自然能力</p><p>以扭曲感染为基础的发展出来进阶技术，和扭曲感染技术一样，能以视频、录音、文字等形式制作可以将【认知操控】系列技术作用于观看者的模因媒介，每次制作需要消耗一个小时，并且只有你亲自制造的那份媒介具有作用，其余复制品没有任何作用。以这种方式发动的【认知扭曲】会保留原本一切效果的，并且模因媒介的有效期能够持续到其被完全破坏为止，但是同一份模因媒介对于每个人只能生效一次。</p><p>【心灵排毒】</p><p>发动前提：具有人格面具能力、人格面具等级为S级</p><p>以足够强大的心灵力量将一切对自身有害的效果从认知层面解除，可以防止变形、创伤、毒素/药物、附身、幻像、疾病、影响心灵、诅咒、时空、命运、环境、信息、完美这十二种来源的负面效果，并且不会阻止这些来源的正面效果，这视为S级对应来源的免疫。即便承受了不在这十二种来源的负面效果，也能临时获得任意一种S级的负面效果免疫，但是同时只能获得一种，每轮切换一次。（负面效果免疫：定身、混乱、即死等无来源的负面效果）</p><p>【神灵权柄】</p><p>发动前提：具有人格面具能力、人格面具等级为S级、具有构筑心之海的能力（人格面具能力）</p><p>以神灵级别强大的心灵力量并配合认知诃学的知识而发展出的综合能力，包含【心海之神】、【认知复活】、【存在清除】、【虚实结合】这四种能力。</p><p>【心海之神】</p><p>通过心之海可将【认知操控】系列技术作用与每一个连接心之海的目标，同时由于该系列技术带来的经验，能对心之海本身进行掌控，使其中构筑一个认知实体化的异世界，异世界的结构和样貌由其连接的每个个体决定，同时作为构筑者也能将其改造成自身所想的样貌，以上效果视为SSSSS级思维控制效果和SSSSS级异世界效果。</p><p>【认知复活】</p><p>通过死亡目标在集体或个体的认知存在，将其复活，即便是灵魂和肉体都被完全摧毁，只有还有人具有对目标的认知，就可以将其复活，但可能会因为认知上偏差导致复活后目标的记忆与性格会所改变。这种复活能力作用范围为心之海的影响范围，每次可复活的目标数不限，每轮只能发动一次，视为SSSSS级复活效果。</p><p>【存在清除】</p><p>通过将目标在集体或个体的认知存在清除，可在现实中同步将目标的存在清除。能力的发动需要消耗标准动作，然后以【认知诃学】检定或【人格面具】检定对抗每个具有目标认知的个体，对方以意志豁免对抗，作用范围为心之海的影响范围，视为心灵来源SSSSS级即死效果。</p><p>【虚实结合】</p><p>通过对现实在集体的认知替换，可在将现实替换成你指定现实，通过这种方式可以对现实环境进行修改，也可以将认知实体化的异世界替换现实，直接使异世界成为集体认知的现实，这视为SSSSS级环境效果。      * * *</p><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',66)])])}const P=a(o,[["render",s]]);export{f as __pageData,P as default};
